```ts
import { spawn } from "node:child_process";
import type {
	ContextUsage,
	ExtensionAPI,
	ExtensionCommandContext,
} from "@earendil-works/pi-coding-agent";

type QManagerAction = "start-next" | "continue";

type ParsedArgs = {
	action: QManagerAction;
	passthrough: string[];
};

type QManagerCompactionSignal = {
	started: boolean;
	handoffPath?: string;
	readyCommand?: string;
};

type QManagerCLIResult = {
	exitCode: number;
	stdout: string;
	stderr: string;
	compaction: QManagerCompactionSignal;
};

export default function qManagerParentExtension(pi: ExtensionAPI): void {
	pi.registerCommand("q-manager", {
		description: "Run Vamos q-manager with parent Pi usage sampling and native compaction",
		handler: async (args, ctx) => {
			const parsed = parseArgs(args);
			const usageFlags = usageFlagsFromContext(ctx.getContextUsage());
			const result = await runQManagerCLI(parsed.action, parsed.passthrough, usageFlags, ctx.cwd);
			sendCLIOutput(pi, parsed.action, result);
			if (result.exitCode !== 0) {
				throw new Error(`q-manager ${parsed.action} failed with exit ${result.exitCode}`);
			}
			compactParent(ctx, result.compaction);
		},
	});
}

function parseArgs(args: string): ParsedArgs {
	const parts = splitArgs(args);
	const action = parts.shift();
	if (action !== "start-next" && action !== "continue") {
		throw new Error("usage: /q-manager <start-next|continue> [vamos qrspi flags]");
	}
	return { action, passthrough: parts };
}

function splitArgs(input: string): string[] {
	const args: string[] = [];
	let current = "";
	let quote: "'" | '"' | undefined;
	let escaping = false;
	for (const char of input.trim()) {
		if (escaping) {
			current += char;
			escaping = false;
			continue;
		}
		if (char === "\\" && quote !== "'") {
			escaping = true;
			continue;
		}
		if ((char === '"' || char === "'") && quote === undefined) {
			quote = char;
			continue;
		}
		if (quote === char) {
			quote = undefined;
			continue;
		}
		if (quote === undefined && /\s/.test(char)) {
			if (current !== "") {
				args.push(current);
				current = "";
			}
			continue;
		}
		current += char;
	}
	if (quote !== undefined) {
		throw new Error("unterminated quote in /q-manager arguments");
	}
	if (escaping) current += "\\";
	if (current !== "") args.push(current);
	return args;
}

function usageFlagsFromContext(usage: ContextUsage | undefined): string[] {
	if (usage?.percent !== null && usage?.percent !== undefined && Number.isFinite(usage.percent)) {
		return ["--manager-usage-percent", usage.percent.toFixed(1)];
	}
	if (usage?.tokens !== null && usage?.tokens !== undefined && usage.contextWindow > 0) {
		return [
			"--manager-usage-tokens",
			String(Math.round(usage.tokens)),
			"--manager-usage-window",
			String(Math.round(usage.contextWindow)),
		];
	}
	return [];
}

function runQManagerCLI(
	action: QManagerAction,
	args: string[],
	usageFlags: string[],
	cwd: string,
): Promise<QManagerCLIResult> {
	const cliArgs = ["qrspi", action, ...args, ...usageFlags];
	return new Promise((resolve, reject) => {
		const child = spawn("vamos", cliArgs, { cwd, stdio: ["ignore", "pipe", "pipe"] });
		let stdout = "";
		let stderr = "";
		child.stdout.setEncoding("utf8");
		child.stderr.setEncoding("utf8");
		child.stdout.on("data", (chunk: string) => {
			stdout += chunk;
		});
		child.stderr.on("data", (chunk: string) => {
			stderr += chunk;
		});
		child.on("error", reject);
		child.on("close", (code) => {
			resolve({
				exitCode: code ?? 1,
				stdout,
				stderr,
				compaction: parseCompactionSignal(stdout),
			});
		});
	});
}

function parseCompactionSignal(stdout: string): QManagerCompactionSignal {
	const signal: QManagerCompactionSignal = { started: false };
	for (const rawLine of stdout.split(/\r?\n/)) {
		const line = rawLine.trim();
		if (line === "q-manager-parent-compact: started") {
			signal.started = true;
		} else if (line.startsWith("handoff:")) {
			signal.handoffPath = line.slice("handoff:".length).trim();
		} else if (line.startsWith("ready:")) {
			signal.readyCommand = line.slice("ready:".length).trim();
		}
	}
	return signal;
}

function sendCLIOutput(pi: ExtensionAPI, action: QManagerAction, result: QManagerCLIResult): void {
	const output = [result.stdout.trim(), result.stderr.trim()].filter(Boolean).join("\n\n");
	pi.sendMessage({
		customType: "q-manager-cli-output",
		content: output === "" ? `q-manager ${action}: no output` : `q-manager ${action}:\n\n\`\`\`text\n${output}\n\`\`\``,
		display: true,
		details: { action, exitCode: result.exitCode, compaction: result.compaction },
	});
}

function compactParent(ctx: ExtensionCommandContext, signal: QManagerCompactionSignal): void {
	if (!signal.started) return;
	const handoff = signal.handoffPath ?? "the q-manager operational handoff printed by the CLI";
	const ready = signal.readyCommand ?? "vamos qrspi manager-ready --state-file <state> --manager-pane $TMUX_PANE";
	ctx.ui.notify("q-manager parent compaction started", "info");
	ctx.compact({
		customInstructions: `Read q-manager operational handoff: ${handoff}.\nAfter compaction, run exactly once:\n${ready}\nThen follow any flushed q_manager_child_wake.`,
		onComplete: () => ctx.ui.notify("q-manager parent compaction complete", "info"),
		onError: (error) => ctx.ui.notify(`q-manager parent compaction failed: ${error.message}`, "error"),
	});
}
```

Implementation notes:

- The parent wrapper samples usage before the CLI call; do not reuse `LastManagerUsage` for decisions.
- The wrapper passes no usage flags when Pi reports `percent=null` and `tokens=null` after compaction.
- Native `ctx.compact()` fires only after exit code 0 and `q-manager-parent-compact: started` appears in stdout.
- The wrapper should not duplicate graph transitions, parse QRSPI YAML, or inspect child session JSONL.
- If local dev needs `go run ./cmd/vamos-runtime`, add a documented environment seam only after review (for example `VAMOS_Q_MANAGER_BIN`); avoid shell-eval strings in the first implementation.

